<?php require_once __DIR__ . '/includes/admin-header.php';
if($_SERVER['REQUEST_METHOD']==='POST'){ validar_csrf(); if(isset($_POST['excluir'])){$pdo->prepare('DELETE FROM ceps_entrega WHERE id=?')->execute([$_POST['id']]); registrar_log($pdo,'CEPs','Excluiu faixa ID '.$_POST['id']);}else{$ini=cep_para_int($_POST['cep_inicio']);$fim=cep_para_int($_POST['cep_fim']);$pdo->prepare('INSERT INTO ceps_entrega (cep_inicio,cep_fim,cep_inicio_num,cep_fim_num,descricao,ativo,criado_em) VALUES (?,?,?,?,?,?,NOW())')->execute([$_POST['cep_inicio'],$_POST['cep_fim'],$ini,$fim,$_POST['descricao'],isset($_POST['ativo'])?1:0]); registrar_log($pdo,'CEPs','Criou faixa '.$_POST['cep_inicio'].' a '.$_POST['cep_fim']);}}
$ceps=$pdo->query('SELECT * FROM ceps_entrega ORDER BY id DESC')->fetchAll();
?>
<h1>CEPs de entrega</h1><div class="grid-2"><section class="panel"><h2>Nova faixa</h2><form method="post" class="form-grid"><input type="hidden" name="csrf_token" value="<?= csrf_token() ?>"><label>CEP inicial<input name="cep_inicio" placeholder="26100-001" required></label><label>CEP final<input name="cep_fim" placeholder="26199-999" required></label><label class="wide">Descrição<input name="descricao" placeholder="Região de entrega"></label><label class="check"><input type="checkbox" name="ativo" checked> Ativo</label><button class="btn primary">Salvar faixa</button></form></section><section class="panel"><h2>Faixas cadastradas</h2><div class="table-wrap"><table><thead><tr><th>Início</th><th>Fim</th><th>Descrição</th><th></th></tr></thead><tbody><?php foreach($ceps as $c): ?><tr><td><?= e($c['cep_inicio']) ?></td><td><?= e($c['cep_fim']) ?></td><td><?= e($c['descricao']) ?></td><td><form method="post"><input type="hidden" name="csrf_token" value="<?= csrf_token() ?>"><input type="hidden" name="id" value="<?= (int)$c['id'] ?>"><button name="excluir">Excluir</button></form></td></tr><?php endforeach; ?></tbody></table></div></section></div><?php require_once __DIR__ . '/includes/admin-footer.php'; ?>
